def test_case(pred_sqls, sol_sqls, db_path, conn, conditions):
    # Get all table names first
    tables_query = "SELECT name FROM sqlite_master WHERE type='table' AND name NOT LIKE 'sqlite_%';"
    tables_result, exec_err, timeout_err = execute_queries([tables_query], db_path, conn, logger=None)

    if exec_err or timeout_err:
        raise AssertionError("Failed to retrieve table names")

    # For each table, get its column information
    non_lowercase_columns = []

    if tables_result and len(tables_result) > 0:
        for table_row in tables_result[0]:
            table_name = table_row[0]
            pragma_query = f"PRAGMA table_info('{table_name}');"
            column_info, exec_err, timeout_err = execute_queries([pragma_query], db_path, conn, logger=None)

            if exec_err or timeout_err:
                raise AssertionError(f"Failed to retrieve column information for table {table_name}")

            # Check each column name
            if column_info and len(column_info) > 0:
                for col_row in column_info[0]:
                    col_name = col_row[1]  # Column name is at index 1
                    if col_name != col_name.lower():
                        non_lowercase_columns.append(f"{table_name}.{col_name}")

    # If issue_sql is being tested, it should fail (have non-lowercase columns)
    if 'First_Name' in str(pred_sqls):
        assert len(non_lowercase_columns) > 0, "issue_sql should demonstrate a problem with non-lowercase column names"
    # If sol_sql is being tested, it should pass (all columns lowercase)
    else:
        assert len(non_lowercase_columns) == 0, f"Found non-lowercase column names: {non_lowercase_columns}"

    return 1

